css:
body {
    font-family: Arial, sans-serif;
    font-size: 14px;
    margin: 0;
    padding: 10px;
}

.label-container {
    display: flex;
    flex-wrap: wrap;
    justify-content: space-between;
    gap: 20px;
}

.label {
    width: 100%; /* For 2 per row (use 31% for 3 per row) */
    border: 1px solid #000;
    padding: 8px;
    box-sizing: border-box;
    page-break-inside: avoid;
}

table {
    width: 100%;
    border-collapse: collapse;
}

td {
    border: 1px solid #000;
    padding: 4px;
    vertical-align: top;
}

.qr-img, .barcode-img {
    width: 100px;
    height: auto;
    display: block;
    margin: 0 auto;
}

@media print {
    .label {
        page-break-inside: avoid;
    }
}
